import {Node} from 'jibo-kb';
import {Event, EventContainer} from 'jibo-typed-events';

export type ErrCallback = (err)=>void;
export type MediaListCallback = (err, media?:MediaNode[])=>void;
export type MediaNodeCallback = (err, media?:MediaNode)=>void;

export enum ThumbnailType {
    thumb,
    thumb_robot
}

export enum MediaType {
    image,
    recording,
    thumb,
    thumb_robot,
    audio
}

export class MediaNode extends Node {
    public data: {
        path:string,
        type:MediaType,
        reference:string,
        accountId:string,
        loopId:string,
        url:string,
        isEncrypted:boolean,
        isDeleted:boolean,
        created:number
    };
    public readonly id:string;
    public readonly loopId:string;
    public readonly url:string;
    public getThumbnailId(type?:ThumbnailType):string;
}

declare class MediaModelEvents extends EventContainer {
    public mediaListChanged: Event<void>;
}

export const events:MediaModelEvents;

export function loadMedia(callback:MediaListCallback):void;
export function loadMedia():Promise<MediaNode[]>;
export function loadMediaAll(callback:MediaListCallback):void;
export function loadMediaAll():Promise<MediaNode[]>;
export function loadThumbnail(mediaNode:MediaNode, callback:MediaNodeCallback):void;
export function loadThumbnail(mediaNode:MediaNode, type:ThumbnailType, callback:MediaNodeCallback):void;
export function loadThumbnail(mediaNode:MediaNode, type:ThumbnailType):Promise<MediaNode>;
export function getThumbnailUrl(mediaNode:MediaNode, type?:ThumbnailType):string;
export function downloadThumbnails(ids:string[], callback:ErrCallback):void;
export function downloadThumbnails(ids:string[]):Promise<void>;
export function downloadPhoto(id:string, callback:ErrCallback):void;
export function downloadPhoto(id:string):Promise<void>;
export function storePhoto(callback:ErrCallback):void;
export function storePhoto():Promise<void>;
export function deletePhoto(id:string, callback:ErrCallback):void;
export function deletePhoto(id:string):Promise<void>;
